import { useState } from "react"
import * as XLSX from "xlsx"

// ── Template Excel hardcodeado en base64 ────────────────────────────────────
const TEMPLATE_B64 = ""

function b64ToArrayBuffer(b64) {
  const bin = atob(b64)
  const buf = new ArrayBuffer(bin.length)
  const view = new Uint8Array(buf)
  for (let i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i)
  return buf
}

const GESTORIA = 650

function fmtE(n) {
  const num = parseFloat(n) || 0
  return new Intl.NumberFormat("es-ES", { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(num) + " €"
}

function calculate(mode, form) {
  const D28 = parseFloat(form.precioVenta) || 0
  const D25 = D28 - GESTORIA
  const D24 = D25 - D25 / 1.21
  const D23 = D25 / 1.21
  const E16 = mode === "VO" ? D23 : D25
  const accSum = form.accesorios.reduce((s, a) => s + (parseFloat(a.value) || 0), 0)
  const E23 = E16 + accSum
  const E24 = mode === "VO" ? E23 * 0.21 : 0
  const E25 = E23 + E24
  const G28 = E25 + GESTORIA
  return { D23, D24, D25, D28, E16, E23, E24, E25, G28 }
}

function fillAndDownload(mode, form) {
  const buf = b64ToArrayBuffer(TEMPLATE_B64)
  const wb = XLSX.read(buf, { type: "array", cellStyles: true, cellNF: true })

  const sheetName = mode === "VO" ? "VO" : "RBU"
  const ws = wb.Sheets[sheetName]

  function setCell(addr, value, type) {
    const ex = ws[addr] || {}
    ws[addr] = { ...ex, v: value, t: type || (typeof value === "number" ? "n" : "s"), ...(ex.z ? { z: ex.z } : {}), ...(ex.s ? { s: ex.s } : {}) }
  }
  const str = (addr, v) => { if (v && String(v).trim()) setCell(addr, String(v), "s") }
  const num = (addr, v) => { const n = parseFloat(v) || 0; if (n) setCell(addr, n, "n") }

  str("D5", form.centro);   str("G5", form.vendedor)
  str("E7", form.nombre);   str("E8", form.dni);   str("I8", form.tel)
  str("E9", form.direccion); str("D10", form.cp);  str("G10", form.poblacion)
  str("D12", form.vsb);     str("G12", form.modelo)
  str("D13", form.procedencia); str("G13", form.matricula)
  num("D28", parseFloat(form.precioVenta) || 0)
  if (form.coste) num("F16", parseFloat(form.coste))

  const accCells = ["E17","E18","E19","E20","E21","E22"]
  const lblCells = ["C17","C18","C19","C20","C21","C22"]
  form.accesorios.forEach((a, i) => {
    if (a.value && parseFloat(a.value)) num(accCells[i], parseFloat(a.value))
    if (a.label) str(lblCells[i], a.label)
  })

  str("J17", form.mantenimiento || "SIN")
  if (form.baliza) num("J18", parseFloat(form.baliza) || 32)
  if (form.accesorio) str("J19", form.accesorio)
  if (form.varios1)   str("J20", form.varios1)
  if (form.varios2)   str("J21", form.varios2)
  str("J24", form.avisador || "SIN")

  num("E31", parseFloat(form.voValor) || 0)
  if (form.voMatricula) str("G31", form.voMatricula)
  if (form.ps) num("E32", parseFloat(form.ps))

  const pagoAddrs = ["E33","E34","E35"]
  form.pagos.forEach((p, i) => { if (p.importe && parseFloat(p.importe)) num(pagoAddrs[i], parseFloat(p.importe)) })

  if (form.entidad)   str("H33", form.entidad)
  if (form.importeFin) num("H34", parseFloat(form.importeFin))
  if (form.plazo)     str("H35", form.plazo)
  if (form.cuota)     str("H36", form.cuota)
  if (form.tipo)      str("H37", form.tipo)
  if (form.margen)    num("F40", parseFloat(form.margen))

  const out = XLSX.write(wb, { type: "array", bookType: "xlsx", cellStyles: true })
  const blob = new Blob([out], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" })
  const url = URL.createObjectURL(blob)
  const a = document.createElement("a")
  a.href = url; a.download = `Propuesta_${form.matricula || "cliente"}_${mode}.xlsx`; a.click()
  URL.revokeObjectURL(url)
}

export default function App() {
  const [mode, setMode] = useState("RBU")
  const [loading, setLoading] = useState(false)
  const [form, setForm] = useState({
    nombre: "", dni: "", tel: "", direccion: "", cp: "", poblacion: "",
    vsb: "", modelo: "", matricula: "", procedencia: "VO",
    centro: "Sant Boi", vendedor: "Ricardo Torrente",
    precioVenta: "", coste: "",
    accesorios: [
      { label: "EXT GARANTIA", value: "" }, { label: "ACCESORIOS", value: "" },
      { label: "TALLER", value: "" },        { label: "TALLER", value: "" },
      { label: "VARIOS", value: "" },        { label: "VARIOS", value: "" },
    ],
    mantenimiento: "SIN", baliza: "32", accesorio: "", varios1: "", varios2: "", avisador: "SIN",
    voValor: "", voMatricula: "", ps: "",
    pagos: [{ importe: "" }, { importe: "" }, { importe: "" }],
    entidad: "", importeFin: "", plazo: "", cuota: "", tipo: "", margen: "",
  })

  const upd = (k, v) => setForm(f => ({ ...f, [k]: v }))
  const updAcc = (i, k, v) => setForm(f => { const a = [...f.accesorios]; a[i] = { ...a[i], [k]: v }; return { ...f, accesorios: a } })
  const updPago = (i, k, v) => setForm(f => { const p = [...f.pagos]; p[i] = { ...p[i], [k]: v }; return { ...f, pagos: p } })

  const switchMode = (m) => { setMode(m); updAcc(0, "label", m === "RBU" ? "EXT GARANTIA" : "ACCESORIOS") }

  const extractPDF = async (file) => {
    if (!file) return
    setLoading(true)
    try {
      const base64 = await new Promise((res, rej) => { const r = new FileReader(); r.onload = () => res(r.result.split(",")[1]); r.onerror = rej; r.readAsDataURL(file) })
      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, messages: [{ role: "user", content: [
          { type: "document", source: { type: "base64", media_type: "application/pdf", data: base64 } },
          { type: "text", text: "Extrae datos de este PDF de Motor Llansà. SOLO JSON sin markdown:\n{\"nombre\":\"\",\"dni\":\"\",\"tel\":\"\",\"direccion\":\"\",\"cp\":\"\",\"poblacion\":\"\",\"modelo\":\"\",\"matricula\":\"\",\"vsb\":\"\",\"precioVenta\":0,\"vendedor\":\"\",\"centro\":\"\"}" }
        ]}] })
      })
      const data = await resp.json()
      const txt = data.content.filter(b => b.type === "text").map(b => b.text).join("")
      const parsed = JSON.parse(txt.replace(/```json|```/g, "").trim())
      setForm(f => ({ ...f, ...parsed, precioVenta: String(parsed.precioVenta || "") }))
    } catch (e) { console.error(e) }
    setLoading(false)
  }

  const calc = calculate(mode, form)
  const voVal = parseFloat(form.voValor) || 0
  const psVal = parseFloat(form.ps) || 0
  const totalPagos = form.pagos.reduce((s, p) => s + (parseFloat(p.importe) || 0), 0)
  const pendiente = calc.G28 - voVal - psVal - totalPagos

  return (
    <div style={{ padding: "1.5rem", maxWidth: 640, margin: "0 auto" }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontFamily: "Arial Black, Arial", fontSize: 17, fontWeight: 900, fontStyle: "italic" }}>motorLLansà</span>
          {["VO", "RBU"].map(m => (
            <button key={m} onClick={() => switchMode(m)} style={{
              padding: "3px 13px", fontSize: 11, border: "1px solid #bbb", borderRadius: 4, cursor: "pointer",
              background: mode === m ? "#1a4a8a" : "white", color: mode === m ? "white" : "#333", fontWeight: mode === m ? 700 : 400
            }}>{m}</button>
          ))}
        </div>
        <button onClick={() => fillAndDownload(mode, form)} style={{
          padding: "7px 18px", fontSize: 12, fontWeight: 700, border: "none", borderRadius: 4,
          cursor: "pointer", background: "#1a4a8a", color: "white"
        }}>⬇ Descargar Excel</button>
      </div>

      <div style={{ background: "#eef7f0", border: "1px solid #b8dfc4", borderRadius: 6, padding: "8px 12px", fontSize: 11, marginBottom: 16, color: "#1a5a2a" }}>
        Rellena el formulario → <strong>Descargar Excel</strong> → Abre en Excel → Archivo → Exportar como PDF
      </div>

      {/* PDF extractor */}
      <Sec t="Cargar datos desde PDF del pedido (opcional)">
        <label style={{ display: "block", border: "1.5px dashed #b0bcd0", borderRadius: 6, padding: "12px", textAlign: "center", cursor: loading ? "wait" : "pointer", background: "#f5f8ff", fontSize: 12 }}>
          <input type="file" accept=".pdf" style={{ display: "none" }} onChange={e => extractPDF(e.target.files[0])} />
          {loading ? <span style={{ color: "#1a4a8a", fontWeight: 600 }}>Extrayendo con IA…</span>
            : <span>📄 Sube el PDF del pedido y los datos se rellenarán automáticamente</span>}
        </label>
      </Sec>

      <Sec t="Centro y vendedor">
        <R2><F l="Centro" v={form.centro} c={v => upd("centro", v)} /><F l="Vendedor" v={form.vendedor} c={v => upd("vendedor", v)} /></R2>
      </Sec>

      <Sec t="Datos del cliente">
        <F l="Nombre completo" v={form.nombre} c={v => upd("nombre", v)} full />
        <R2><F l="DNI / NIF" v={form.dni} c={v => upd("dni", v)} /><F l="Teléfono" v={form.tel} c={v => upd("tel", v)} /></R2>
        <F l="Dirección" v={form.direccion} c={v => upd("direccion", v)} full />
        <R2><F l="CP" v={form.cp} c={v => upd("cp", v)} /><F l="Población" v={form.poblacion} c={v => upd("poblacion", v)} /></R2>
      </Sec>

      <Sec t="Datos del vehículo">
        <R2><F l="VSB / Nº Stock" v={form.vsb} c={v => upd("vsb", v)} /><F l="Matrícula" v={form.matricula} c={v => upd("matricula", v)} /></R2>
        <R2><F l="Modelo" v={form.modelo} c={v => upd("modelo", v)} /><F l="Procedencia" v={form.procedencia} c={v => upd("procedencia", v)} /></R2>
      </Sec>

      <Sec t="Precio">
        <R2>
          <F l="Precio venta total (IVA incl.)" v={form.precioVenta} c={v => upd("precioVenta", v)} t="number" />
          <F l="Coste interno" v={form.coste} c={v => upd("coste", v)} t="number" />
        </R2>
        <div style={{ background: "#eef3fb", border: "1px solid #c5d9f1", borderRadius: 5, padding: "8px 12px", fontSize: 11 }}>
          <CR l={mode === "VO" ? "PFF vehículo (B.I.)" : "PFF vehículo (neto)"} v={fmtE(calc.E16)} />
          {mode === "VO" && <CR l="IVA vehículo 21%" v={fmtE(calc.D24)} />}
          <CR l="B.I. total (con accesorios)" v={fmtE(calc.E23)} />
          <CR l="IVA 21% total" v={fmtE(calc.E24)} />
          <CR l="Gestoría (fija)" v={fmtE(GESTORIA)} />
          <CR l="TOTAL CON ACCESORIOS" v={fmtE(calc.G28)} bold />
        </div>
      </Sec>

      <Sec t={`Líneas adicionales (${mode === "VO" ? "B.I. sin IVA" : "precio final"})`}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 90px", gap: "4px 8px" }}>
          <div style={{ fontSize: 10, color: "#666", fontWeight: 600 }}>Concepto</div>
          <div style={{ fontSize: 10, color: "#666", fontWeight: 600, textAlign: "right" }}>Importe</div>
          {form.accesorios.map((a, i) => (<>
            <input key={"l"+i} value={a.label} onChange={e => updAcc(i, "label", e.target.value)} style={{ fontSize: 12, padding: "4px 6px", border: "1px solid #ddd", borderRadius: 3 }} />
            <input key={"v"+i} value={a.value} onChange={e => updAcc(i, "value", e.target.value)} type="number" placeholder="0" style={{ fontSize: 12, padding: "4px 6px", border: "1px solid #ddd", borderRadius: 3, textAlign: "right" }} />
          </>))}
        </div>
      </Sec>

      <Sec t="Obsequios">
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          <F l="Mantenimiento (SIN / valor)" v={form.mantenimiento} c={v => upd("mantenimiento", v)} />
          <F l="Pack Baliza (€)" v={form.baliza} c={v => upd("baliza", v)} t="number" />
          <F l="Accesorio" v={form.accesorio} c={v => upd("accesorio", v)} />
          <F l="Avisador (SIN / valor)" v={form.avisador} c={v => upd("avisador", v)} />
          <F l="Varios 1" v={form.varios1} c={v => upd("varios1", v)} />
          <F l="Varios 2" v={form.varios2} c={v => upd("varios2", v)} />
        </div>
      </Sec>

      <Sec t="VO a cambio">
        <R2>
          <F l="Matrícula VO" v={form.voMatricula} c={v => upd("voMatricula", v)} />
          <F l="Valor VO (€)" v={form.voValor} c={v => upd("voValor", v)} t="number" />
          <F l="P/S (€)" v={form.ps} c={v => upd("ps", v)} t="number" />
        </R2>
      </Sec>

      <Sec t="Forma de pago">
        <R2>
          <F l="Pago 1 (€)" v={form.pagos[0].importe} c={v => updPago(0, "importe", v)} t="number" />
          <F l="Pago 2 (€)" v={form.pagos[1].importe} c={v => updPago(1, "importe", v)} t="number" />
          <F l="Pago 3 (€)" v={form.pagos[2].importe} c={v => updPago(2, "importe", v)} t="number" />
        </R2>
        <R2 style={{ marginTop: 6 }}>
          <F l="Entidad" v={form.entidad} c={v => upd("entidad", v)} />
          <F l="Importe financiado (€)" v={form.importeFin} c={v => upd("importeFin", v)} t="number" />
        </R2>
        <R2>
          <F l="Plazo (meses)" v={form.plazo} c={v => upd("plazo", v)} />
          <F l="Cuota mensual" v={form.cuota} c={v => upd("cuota", v)} />
          <F l="Tipo / TIN" v={form.tipo} c={v => upd("tipo", v)} />
        </R2>
        <div style={{ background: "#eef3fb", border: "1px solid #c5d9f1", borderRadius: 5, padding: "8px 12px", fontSize: 11, marginTop: 8 }}>
          <CR l="Total" v={fmtE(calc.G28)} />
          <CR l="VO + P/S" v={fmtE(voVal + psVal)} />
          <CR l="Pagos" v={fmtE(totalPagos)} />
          <CR l="PENDIENTE" v={fmtE(pendiente)} bold />
        </div>
      </Sec>

      <Sec t="Margen operación">
        <F l="Margen (€)" v={form.margen} c={v => upd("margen", v)} t="number" />
      </Sec>

      <div style={{ textAlign: "right", paddingBottom: "2rem", marginTop: 8 }}>
        <button onClick={() => fillAndDownload(mode, form)} style={{
          padding: "10px 26px", fontSize: 13, fontWeight: 700, border: "none", borderRadius: 5, cursor: "pointer", background: "#1a4a8a", color: "white"
        }}>⬇ Descargar Excel relleno</button>
      </div>
    </div>
  )
}

function Sec({ t, children }) {
  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.07em", color: "#555", marginBottom: 5 }}>{t}</div>
      <div style={{ border: "1px solid #dde", borderRadius: 6, padding: "10px 12px", background: "#fff" }}>{children}</div>
    </div>
  )
}
function R2({ children }) { return <div style={{ display: "flex", gap: 8 }}>{children}</div> }
function F({ l, v, c, t = "text", full }) {
  return (
    <div style={{ flex: full ? "none" : 1, width: full ? "100%" : "auto", marginBottom: 6 }}>
      <label style={{ display: "block", fontSize: 10, color: "#666", marginBottom: 2 }}>{l}</label>
      <input type={t} value={v} onChange={e => c(e.target.value)} style={{ width: "100%", boxSizing: "border-box", fontSize: 12, padding: "4px 7px", border: "1px solid #ccc", borderRadius: 3 }} />
    </div>
  )
}
function CR({ l, v, bold }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", padding: "2px 0", borderTop: bold ? "1px solid #c5d9f1" : "none", marginTop: bold ? 4 : 0 }}>
      <span style={{ color: bold ? "#000" : "#555", fontWeight: bold ? 700 : 400 }}>{l}</span>
      <strong style={{ fontWeight: bold ? 700 : 500 }}>{v}</strong>
    </div>
  )
}
